  1	import React, { FC, MouseEventHandler, useState } from 'react';
  2	import { useHistory } from 'react-router';
  3	import NodeNetworkConfigurationPolicyModel from 'src/console-models/NodeNetworkConfigurationPolicyModel';
  4	import { getResourceUrl } from 'src/utils/helpers';
  5	import { useNMStateTranslation } from 'src/utils/hooks/useNMStateTranslation';
  6	import { useImmer } from 'use-immer';
  7	
  8	import { k8sCreate } from '@openshift-console/dynamic-plugin-sdk';
  9	import {
 10	  ActionGroup,
 11	  Alert,
 12	  AlertVariant,
 13	  Button,
 14	  ButtonType,
 15	  ButtonVariant,
 16	  PageSection,
 17	  PageSectionVariants,
 18	  Title,
 19	} from '@patternfly/react-core';
 20	import {
 21	  InterfaceType,
 22	  NodeNetworkConfigurationInterface,
 23	  V1NodeNetworkConfigurationPolicy,
 24	} from '@types';
 25	import { NETWORK_STATES } from '@utils/components/PolicyForm/constants';
 26	import PolicyForm from '@utils/components/PolicyForm/PolicyForm';
 27	
 28	import './new-policy.scss';
 29	
 30	const initialPolicy: V1NodeNetworkConfigurationPolicy = {
 31	  apiVersion: `${NodeNetworkConfigurationPolicyModel.apiGroup}/${NodeNetworkConfigurationPolicyModel.apiVersion}`,
 32	  kind: NodeNetworkConfigurationPolicyModel.kind,
 33	  metadata: {
 34	    name: 'policy-name',
 35	  },
 36	  spec: {
 37	    desiredState: {
 38	      interfaces: [
 39	        {
 40	          name: 'br0',
 41	          type: InterfaceType.LINUX_BRIDGE,
 42	          state: NETWORK_STATES.Up,
 43	          bridge: {
 44	            options: {
 45	              stp: {
 46	                enabled: false,
 47	              },
 48	            },
 49	          },
 50	        } as NodeNetworkConfigurationInterface,
 51	      ],
 52	    },
 53	  },
 54	};
 55	
 56	const NewPolicy: FC = () => {
 57	  const { t } = useNMStateTranslation();
 58	  const [policy, setPolicy] = useImmer(initialPolicy);
 59	  const [loading, setLoading] = useState(false);
 60	  const [error, setError] = useState<Error>(undefined);
 61	  const history = useHistory();
 62	
 63	  const onFormSubmit: MouseEventHandler<HTMLButtonElement> = (event) => {
 64	    event.preventDefault();
 65	    setLoading(true);
 66	    return k8sCreate({
 67	      model: NodeNetworkConfigurationPolicyModel,
 68	      data: policy,
 69	    })
 70	      .then(() =>
 71	        history.push(
 72	          getResourceUrl({ model: NodeNetworkConfigurationPolicyModel, resource: policy }),
 73	        ),
 74	      )
 75	      .catch(setError)
 76	      .finally(() => setLoading(false));
 77	  };
 78	
 79	  const goToYAMLEditor = () => {
 80	    const baseUrl = getResourceUrl({ model: NodeNetworkConfigurationPolicyModel });
 81	    history.push(`${baseUrl}~new`);
 82	  };
 83	
 84	  return (
 85	    <PageSection className="new-policy-content" variant={PageSectionVariants.light}>
 86	      <Title className="new-policy-content__h1" headingLevel="h1">
 87	        {t('Create NodeNetworkConfigurationPolicy')}
 88	
 89	        <Button variant={ButtonVariant.link} onClick={goToYAMLEditor}>
 90	          {t('Edit YAML')}
 91	        </Button>
 92	      </Title>
 93	
 94	      <PolicyForm
 95	        policy={policy}
 96	        setPolicy={setPolicy}
 97	        createForm={true}
 98	        formId="create-policy-form"
 99	      />
100	
101	      {error && (
102	        <Alert
103	          variant={AlertVariant.danger}
104	          title={t('Create NodeNetworkConfigurationPolicy error')}
105	          isInline
106	        >
107	          {error.message}
108	        </Alert>
109	      )}
110	
111	      <ActionGroup className="pf-v6-c-form" form="">
112	        <Button
113	          isDisabled={loading}
114	          type={ButtonType.submit}
115	          variant={ButtonVariant.primary}
116	          onClick={onFormSubmit}
117	          isLoading={loading}
118	          form="create-policy-form"
119	        >
120	          {t('Create')}
121	        </Button>
122	
123	        <Button onClick={history.goBack} variant={ButtonVariant.secondary}>
124	          {t('Cancel')}
125	        </Button>
126	      </ActionGroup>
127	    </PageSection>
128	  );
129	};
130	
131	export default NewPolicy;

